const express = require('express');
const session = require('express-session');
const jwt = require('jsonwebtoken');
const axios = require('axios');
const querystring = require('querystring');
const jwksRsa = require('jwks-rsa');

const app = express();
const PORT = process.env.PORT || 3000;

app.use(session({
    secret: 'your_secret_key',
    resave: false,
    saveUninitialized: true,
}));

const OIDC_PROVIDER_URL = 'https://your-oidc-provider.com';
const CLIENT_ID = 'your_client_id';
const CLIENT_SECRET = 'your_client_secret';
const REDIRECT_URI = 'http://localhost:3000/callback';

const client = jwksRsa({
    jwksUri: `${OIDC_PROVIDER_URL}/.well-known/jwks.json`
});

function getKey(header, callback) {
    client.getSigningKey(header.kid, (err, key) => {
        const signingKey = key.getPublicKey();
        callback(null, signingKey);
    });
}

app.get('/login', (req, res) => {
    const authUrl = `${OIDC_PROVIDER_URL}/authorize?${querystring.stringify({
        response_type: 'code',
        client_id: CLIENT_ID,
        redirect_uri: REDIRECT_URI,
        scope: 'openid email profile',
    })}`;
    res.redirect(authUrl);
});

app.get('/callback', async (req, res) => {
    const { code } = req.query;

    const tokenResponse = await axios.post(`${OIDC_PROVIDER_URL}/token`, querystring.stringify({
        grant_type: 'authorization_code',
        code,
        redirect_uri: REDIRECT_URI,
        client_id: CLIENT_ID,
        client_secret: CLIENT_SECRET,
    }));

    const idToken = tokenResponse.data.id_token;

    jwt.verify(idToken, getKey, { algorithms: ['RS256'] }, (err, decodedToken) => {
        if (err) {
            return res.status(401).send('Invalid ID Token');
        }

        req.session.user = {
            sub: decodedToken.sub,
            email: decodedToken.email,
            name: decodedToken.name,
        };

        res.redirect('/profile');
    });
});

app.get('/profile', (req, res) => {
    if (!req.session.user) {
        return res.redirect('/login');
    }
    res.json(req.session.user);
});

app.listen(PORT, () => {
    console.log(`Server is running on http://localhost:${PORT}`);
});